SELECT canonical.grouping_id, canonical.event_month, canonical.lag_day, canonical.load_epoch_day, canonical.batch_id, canonical.alt_value, canonical.row_count, canonical.n_curve_eligible, canonical.n_null_event_time, canonical.n_null_load_time_only, canonical.n_negative_clipped, canonical.n_negative_lag_excluded, canonical.n_overflow, canonical.n_join_unmatched, canonical.n_other_exclusions, canonical.n_base_rows, canonical.n_ambiguous_base_rows, canonical.n_compare_mismatch, canonical.max_lookup_dup, canonical.distinct_keys, canonical.min_load_time, canonical.n_staged_rows 
FROM (SELECT grouping(mp_probe.event_month) * $1 + grouping(mp_probe.lag_day) * $2 + grouping(mp_probe.load_epoch_day) * $3 + $4 + $5 AS grouping_id, mp_probe.event_month AS event_month, mp_probe.lag_day AS lag_day, mp_probe.load_epoch_day AS load_epoch_day, max(mp_probe.batch_id) AS batch_id, max(mp_probe.alt_value) AS alt_value, coalesce(sum(mp_probe.is_probe_row), $6) AS row_count, coalesce(sum(mp_probe.is_eligible), $7) AS n_curve_eligible, coalesce(sum(mp_probe.is_null_event_time), $8) AS n_null_event_time, coalesce(sum(mp_probe.is_null_load_time_only), $9) AS n_null_load_time_only, coalesce(sum(mp_probe.is_negative_clipped), $10) AS n_negative_clipped, coalesce(sum(mp_probe.is_negative_lag_excluded), $11) AS n_negative_lag_excluded, coalesce(sum(mp_probe.is_overflow), $12) AS n_overflow, coalesce(sum(mp_probe.is_join_unmatched), $13) AS n_join_unmatched, CAST($14 AS BIGINT) AS n_other_exclusions, coalesce(sum(mp_probe.is_base_row), $15) AS n_base_rows, coalesce(sum(mp_probe.is_ambiguous_base), $16) AS n_ambiguous_base_rows, coalesce(sum(mp_probe.is_compare_mismatch), $17) AS n_compare_mismatch, max(mp_probe.lookup_dup) AS max_lookup_dup, count(*) AS n_staged_rows, CAST(NULL AS BIGINT) AS distinct_keys, min(mp_probe.load_time) AS min_load_time 
FROM mp_probe GROUP BY GROUPING SETS ((mp_probe.event_month, mp_probe.lag_day), (mp_probe.load_epoch_day)) UNION ALL SELECT $18 AS grouping_id, CAST(NULL AS DATE) AS event_month, CAST(NULL AS INTEGER) AS lag_day, CAST(NULL AS DATE) AS load_epoch_day, CAST(NULL AS VARCHAR) AS batch_id, CAST(NULL AS VARCHAR) AS alt_value, coalesce(sum(mp_probe.is_probe_row), $19) AS row_count, coalesce(sum(mp_probe.is_eligible), $20) AS n_curve_eligible, coalesce(sum(mp_probe.is_null_event_time), $21) AS n_null_event_time, coalesce(sum(mp_probe.is_null_load_time_only), $22) AS n_null_load_time_only, coalesce(sum(mp_probe.is_negative_clipped), $23) AS n_negative_clipped, coalesce(sum(mp_probe.is_negative_lag_excluded), $24) AS n_negative_lag_excluded, coalesce(sum(mp_probe.is_overflow), $25) AS n_overflow, coalesce(sum(mp_probe.is_join_unmatched), $26) AS n_join_unmatched, CAST($27 AS BIGINT) AS n_other_exclusions, coalesce(sum(mp_probe.is_base_row), $28) AS n_base_rows, coalesce(sum(mp_probe.is_ambiguous_base), $29) AS n_ambiguous_base_rows, coalesce(sum(mp_probe.is_compare_mismatch), $30) AS n_compare_mismatch, max(mp_probe.lookup_dup) AS max_lookup_dup, count(*) AS n_staged_rows, CAST(NULL AS BIGINT) AS distinct_keys, min(mp_probe.load_time) AS min_load_time 
FROM mp_probe) AS canonical ORDER BY canonical.grouping_id 
 LIMIT $31
